    {
      "type": "heading",
      "attrs": { "level": 2 },
      "content": [{ "type": "text", "text": "Примеры (JavaScript)" }]
    },
    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "// Универсальные помощники для сортировки по ключам\nfunction compareBy(keyFn, { order = 'asc', nulls = 'last', collator } = {}) {\n  return (a, b) => {\n    let ka = keyFn(a);\n    let kb = keyFn(b);\n\n    const isNilA = ka === null || ka === undefined;\n    const isNilB = kb === null || kb === undefined;\n    if (isNilA || isNilB) {\n      if (isNilA && isNilB) return 0;\n      return isNilA ? (nulls === 'first' ? -1 : 1) : (nulls === 'first' ? 1 : -1);\n    }\n\n    const isNaNA = typeof ka === 'number' && Number.isNaN(ka);\n    const isNaNB = typeof kb === 'number' && Number.isNaN(kb);\n    if (isNaNA || isNaNB) {\n      if (isNaNA && isNaNB) return 0;\n      return isNaNA ? 1 : -1; // Помещаем NaN в конец\n    }\n\n    if (collator && typeof ka === 'string' && typeof kb === 'string') {\n      const r = collator.compare(ka, kb);\n      return order === 'asc' ? r : -r;\n    }\n\n    if (ka < kb) return order === 'asc' ? -1 : 1;\n    if (ka > kb) return order === 'asc' ? 1 : -1;\n    return 0;\n  };\n}\n\nfunction compareByMany(...comparators) {\n  return (a, b) => {\n    for (const cmp of comparators) {\n      const r = cmp(a, b);\n      if (r !== 0) return r;\n    }\n    return 0;\n  };\n}\n\n// Данные\nconst users = [\n  { id: 3, firstName: 'Иван', lastName: 'петров', age: 19 },\n  { id: 1, firstName: 'Анна', lastName: 'Петрова', age: 25 },\n  { id: 2, firstName: 'АННА', lastName: 'иванова', age: 25 },\n  { id: 4, firstName: 'Борис', lastName: null, age: undefined },\n];\n\n// 1) По одному ключу (числовому)\nconst byAgeAsc = users.slice().sort(compareBy(u => u.age, { order: 'asc', nulls: 'last' }));\n\n// 2) По строке, без учета регистра и с учетом чисел (natural sort)\nconst collator = new Intl.Collator('ru', { sensitivity: 'base', numeric: true });\nconst byLastInsensitive = users.slice().sort(compareBy(u => u.lastName, { collator, nulls: 'last' }));\n\n// 3) Составной ключ: lastName, затем firstName, затем id\nconst byLast = compareBy(u => u.lastName, { collator, nulls: 'last' });\nconst byFirst = compareBy(u => u.firstName, { collator, nulls: 'last' });\nconst byIdAsc = compareBy(u => u.id);\nconst byFullNameThenId = users.slice().sort(compareByMany(byLast, byFirst, byIdAsc));\n\n// 4) Смешанное направление: дата по убыванию, затем имя по возрастанию\nconst orders = [\n  { createdAt: '2024-05-01', name: 'zeta' },\n  { createdAt: '2024-05-03', name: 'alpha' },\n  { createdAt: '2024-05-03', name: 'bravo' },\n];\nconst byDateDesc = compareBy(o => Date.parse(o.createdAt), { order: 'desc' });\nconst byNameAsc = compareBy(o => o.name, { collator: new Intl.Collator('ru', { sensitivity: 'base' }) });\nconst ordersSorted = orders.slice().sort(compareByMany(byDateDesc, byNameAsc));\n\n// 5) Decorate–Sort–Undecorate (Schwartzian transform) для дорогого ключа\nconst files = [\n  { path: '/a/file9.txt' },\n  { path: '/b/file10.txt' },\n  { path: '/c/file2.txt' },\n];\nconst natCollator = new Intl.Collator('ru', { numeric: true, sensitivity: 'base' });\nconst sortedFiles = files\n  .map(f => ({ f, k: f.path }))         // извлекаем ключ один раз\n  .sort((x, y) => natCollator.compare(x.k, y.k))\n  .map(({ f }) => f);\n\nconsole.log({ byAgeAsc, byLastInsensitive, byFullNameThenId, ordersSorted, sortedFiles });"
        }
      ]
    },

