          "type": "text",
          "text": "users = [\n    {\"id\": 3, \"first\": \"Иван\", \"last\": \"петров\", \"age\": 19},\n    {\"id\": 1, \"first\": \"Анна\", \"last\": \"Петрова\", \"age\": 25},\n    {\"id\": 2, \"first\": \"АННА\", \"last\": \"иванова\", \"age\": 25},\n    {\"id\": 4, \"first\": \"Борис\", \"last\": None, \"age\": None},\n]\n\n# По одному ключу (None в конец)\nsorted_by_age = sorted(users, key=lambda u: (u[\"age\"] is None, u[\"age\"]))\n\n# Составной ключ (лексикографически): last, first, id\nsorted_by_name = sorted(\n    users,\n    key=lambda u: (\n        (u[\"last\"] or \"\").casefold(),\n        (u[\"first\"] or \"\").casefold(),\n        u[\"id\"],\n    ),\n)\n\n# Смешанное направление: убывание по дате и возрастание по имени\norders = [\n    {\"created_at\": \"2024-05-01\", \"name\": \"zeta\"},\n    {\"created_at\": \"2024-05-03\", \"name\": \"alpha\"},\n    {\"created_at\": \"2024-05-03\", \"name\": \"bravo\"},\n]\nfrom datetime import datetime\n\ndef ts(s):\n    return int(datetime.fromisoformat(s).timestamp())\n\nsorted_orders = sorted(\n    orders,\n    key=lambda o: (-ts(o[\"created_at\"]), o[\"name\"].casefold())\n)\n\nprint(sorted_by_age)\nprint(sorted_by_name)\nprint(sorted_orders)"
