      ]
    },
    {
      "type": "heading",
      "attrs": {
        "level": 4
      },
      "content": [
        {
          "type": "text",
          "text": "Пузырьковая сортировка (JS, стабильная, с ранним выходом)"
        }
      ]
    },
    {
      "type": "codeBlock",
      "attrs": {
        "language": "js"
      },
      "content": [
        {
          "type": "text",
          "text": "function bubbleSort(arr, compare = (a, b) => a - b) {\n  const a = arr; // сортируем на месте\n  let n = a.length;\n  let swapped = true;\n  while (swapped) {\n    swapped = false;\n    for (let i = 1; i < n; i++) {\n      if (compare(a[i - 1], a[i]) > 0) {\n        // обмен соседей — стабильность сохраняется\n        [a[i - 1], a[i]] = [a[i], a[i - 1]];\n        swapped = true;\n      }\n    }\n    // последний элемент уже на месте\n    n--;\n  }\n  return a;\n}\n\n// Пример\nconst data1 = [5, 1, 4, 2, 8];\nconsole.log(bubbleSort(data1)); // [1, 2, 4, 5, 8]"
        }
      ]
    },
    {
      "type": "heading",
      "attrs": {
        "level": 4
      },
      "content": [
        {
          "type": "text",
          "text": "Простая обменная сортировка O(n²) (JS) — обмен при каждом нарушении порядка"
        }
      ]
    },
    {
      "type": "codeBlock",
      "attrs": {
        "language": "js"
      },
      "content": [
        {
          "type": "text",
          "text": "function exchangeSort(arr, compare = (a, b) => a - b) {\n  const a = arr; // сортируем на месте\n  const n = a.length;\n  for (let i = 0; i < n - 1; i++) {\n    for (let j = i + 1; j < n; j++) {\n      if (compare(a[i], a[j]) > 0) {\n        // не соседний обмен — алгоритм не стабилен\n        [a[i], a[j]] = [a[j], a[i]];\n      }\n    }\n  }\n  return a;\n}\n\n// Пример\nconst data2 = [3, 2, 1, 2];\nconsole.log(exchangeSort(data2)); // [1, 2, 2, 3]"
        }
      ]
    },
    {
      "type": "heading",
      "attrs": {
        "level": 4
      },
      "content": [
        {
          "type": "text",
          "text": "Быстрая сортировка (Quicksort, partition-exchange, JS)"
        }
      ]
    },
    {
      "type": "codeBlock",
      "attrs": {
        "language": "js"
      },
      "content": [
        {
          "type": "text",
          "text": "function quickSort(arr, compare = (a, b) => a - b, left = 0, right = arr.length - 1) {\n  if (left >= right) return arr;\n\n  const pivot = arr[right]; // Ломуто-разбиение для наглядности\n  let i = left;\n  for (let j = left; j < right; j++) {\n    if (compare(arr[j], pivot) <= 0) {\n      [arr[i], arr[j]] = [arr[j], arr[i]]; // обмены вокруг опорного\n      i++;\n    }\n  }\n  [arr[i], arr[right]] = [arr[right], arr[i]];\n\n  quickSort(arr, compare, left, i - 1);\n  quickSort(arr, compare, i + 1, right);\n  return arr;\n}\n\n// Пример\nconst data3 = [10, 7, 8, 9, 1, 5];\nconsole.log(quickSort(data3)); // [1, 5, 7, 8, 9, 10]"
        }
      ]
    },
    {
      "type": "heading",
      "attrs": {
        "level": 3
      },
      "content": [
        {
          "type": "text",
          "text": "Когда выбирать обменные сортировки"
