  swap A[i], A[min]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример на JavaScript (обычная, неустойчивая версия)"}]},{"type":"codeBlock","attrs":{"language":"js"},"content":[{"type":"text","text":"function selectionSort(arr, compare = (a, b) => a - b) {
  const n = arr.length;
  for (let i = 0; i < n - 1; i++) {
    let minIdx = i;
