        {
          "type": "text",
          "text": "function insertionSort(arr) {\n  for (let i = 1; i < arr.length; i++) {\n    const key = arr[i];\n    let j = i - 1;\n    // Сдвигаем элементы вправо, пока они больше key\n    while (j >= 0 && arr[j] > key) {\n      arr[j + 1] = arr[j];\n      j--;\n    }\n    // Вставляем key на свою позицию\n    arr[j + 1] = key;\n  }\n  return arr;\n}\n\n// Оптимизация: бинарная вставка (меньше сравнений, сдвиги те же)\nfunction binaryInsertionSort(arr) {\n  for (let i = 1; i < arr.length; i++) {\n    const key = arr[i];\n    let left = 0;\n    let right = i; // полуинтервал [left, right)\n\n    // Находим позицию вставки бинарным поиском\n    while (left < right) {\n      const mid = (left + right) >> 1;\n      // <= ставит key после равных — сохраняет стабильность\n      if (arr[mid] <= key) left = mid + 1; else right = mid;\n    }\n\n    // Сдвиг блока вправо на 1, чтобы вставить key\n    for (let j = i; j > left; j--) arr[j] = arr[j - 1];\n    arr[left] = key;\n  }\n  return arr;\n}\n\n// Демонстрация\nconst nums = [5, 2, 4, 6, 1, 3];\nconsole.log(insertionSort([...nums]));        // [1,2,3,4,5,6]\nconsole.log(binaryInsertionSort([...nums]));  // [1,2,3,4,5,6]\n"
        }
