          "text": "function mergeSortBottomUp(a) {\n  const n = a.length;\n  const aux = new Array(n);\n  for (let sz = 1; sz < n; sz <<= 1) {\n    for (let lo = 0; lo < n - sz; lo += sz << 1) {\n      const mid = lo + sz;\n      const hi = Math.min(lo + (sz << 1), n);\n      mergeRange(a, aux, lo, mid, hi);\n    }\n  }\n  return a;\n}\n\nfunction mergeRange(a, aux, lo, mid, hi) {\n  // Копируем в буфер\n  for (let t = lo; t < hi; t++) aux[t] = a[t];\n  let i = lo, j = mid, k = lo;\n  while (i < mid && j < hi) {\n    if (aux[i] <= aux[j]) a[k++] = aux[i++];\n    else a[k++] = aux[j++];\n  }\n  while (i < mid) a[k++] = aux[i++];\n  while (j < hi) a[k++] = aux[j++];\n}\n\n// Пример\nconst arr2 = [7, 1, 4, 9, 0, 3, 8, 2, 6, 5];\nconsole.log(mergeSortBottomUp(arr2));\n"
        }
