          "type": "text",
          "text": "// Базовая версия (возвращает новый массив)\nfunction bubbleSort(arr) {\n  const a = arr.slice();\n  const n = a.length;\n  for (let i = 0; i < n - 1; i++) {\n    for (let j = 0; j < n - 1 - i; j++) {\n      if (a[j] > a[j + 1]) {\n        [a[j], a[j + 1]] = [a[j + 1], a[j]];\n      }\n    }\n  }\n  return a;\n}\n\n// Оптимизированная версия: ранний выход + граница по последней перестановке\nfunction bubbleSortOptimized(arr) {\n  const a = arr.slice();\n  let n = a.length;\n  while (n > 1) {\n    let newN = 0; // позиция последней перестановки\n    for (let j = 0; j < n - 1; j++) {\n      if (a[j] > a[j + 1]) {\n        [a[j], a[j + 1]] = [a[j + 1], a[j]];\n        newN = j + 1;\n      }\n    }\n    if (newN === 0) break; // уже отсортировано\n    n = newN; // хвост после newN уже отсортирован\n  }\n  return a;\n}\n\n// Двусторонняя версия (Cocktail Shaker Sort)\nfunction cocktailShakerSort(arr) {\n  const a = arr.slice();\n  let start = 0;\n  let end = a.length - 1;\n  let swapped = true;\n  while (swapped) {\n    swapped = false;\n    for (let i = start; i < end; i++) {\n      if (a[i] > a[i + 1]) {\n        [a[i], a[i + 1]] = [a[i + 1], a[i]];\n        swapped = true;\n      }\n    }\n    if (!swapped) break;\n    swapped = false;\n    end--;\n    for (let i = end; i > start; i--) {\n      if (a[i - 1] > a[i]) {\n        [a[i - 1], a[i]] = [a[i], a[i - 1]];\n        swapped = true;\n      }\n    }\n    start++;\n  }\n  return a;\n}\n\n// Пример\nconsole.log(bubbleSort([5, 1, 4, 2, 8]));            // [1, 2, 4, 5, 8]\nconsole.log(bubbleSortOptimized([5, 1, 4, 2, 8]));   // [1, 2, 4, 5, 8]\nconsole.log(cocktailShakerSort([5, 1, 4, 2, 8]));    // [1, 2, 4, 5, 8]"
